/* Physics Solved bundle — generated by scripts/build.mjs. Edit src/, not dist/. */
/* --- src/js/core.js --- */
/* Physics Solved — core mount system.
 * Scans the page for [data-ps-app] elements, resolves the CDN base URL,
 * fetches the JSON each component needs, and renders. Vanilla ES2020, no deps.
 * Components register themselves on window.PS via PS.register(name, fn).
 */
(function () {
  "use strict";

  // Capture the <script> that loaded this bundle NOW (synchronously), while
  // document.currentScript is still valid. Used to derive the data base URL.
  var CURRENT = document.currentScript;

  var PS = (window.PS = window.PS || {});
  PS.components = PS.components || {};

  /* ---- Base URL resolution -------------------------------------------- */
  // Priority: data-ps-base attribute on the script tag -> derived from the
  // script src (strip trailing "dist/<file>") -> "" (same-origin relative).
  function resolveBase() {
    var attr = CURRENT && CURRENT.getAttribute && CURRENT.getAttribute("data-ps-base");
    if (attr) return attr.replace(/\/?$/, "/"); // ensure trailing slash
    var src = (CURRENT && CURRENT.src) || "";
    if (!src) return "";
    // .../physics-solved@v1/dist/physics-solved.min.js -> .../physics-solved@v1/
    var base = src.replace(/dist\/[^\/]*$/, "");
    if (base === src) base = src.replace(/[^\/]*$/, ""); // fallback: script dir
    return base;
  }

  PS.base = resolveBase();
  PS.dataUrl = function (path) {
    return PS.base + "data/" + String(path).replace(/^\/+/, "");
  };

  /* ---- Fetch with in-memory cache ------------------------------------- */
  var cache = Object.create(null);
  PS.fetchJSON = function (path) {
    var url = /^https?:|^\.\.?\//.test(path) ? path : PS.dataUrl(path);
    if (cache[url]) return cache[url];
    cache[url] = fetch(url, { credentials: "omit" }).then(function (r) {
      if (!r.ok) throw new Error("PS: failed to load " + url + " (" + r.status + ")");
      return r.json();
    });
    return cache[url];
  };

  PS.getRegistry = function () {
    return PS.fetchJSON("registry.json");
  };

  /* ---- Small DOM helpers ---------------------------------------------- */
  // h("div.cls#id", {attrs}, [children | "text"])
  PS.h = function (spec, attrs, children) {
    var tag = "div", id = null, cls = [];
    spec.replace(/([.#]?[^.#]+)/g, function (m) {
      if (m[0] === ".") cls.push(m.slice(1));
      else if (m[0] === "#") id = m.slice(1);
      else tag = m;
    });
    var node = document.createElement(tag);
    if (id) node.id = id;
    if (cls.length) node.className = cls.join(" ");
    if (attrs) {
      Object.keys(attrs).forEach(function (k) {
        var v = attrs[k];
        if (v == null || v === false) return;
        if (k === "class") node.className += (node.className ? " " : "") + v;
        else if (k === "text") node.textContent = v;
        else if (k === "html") node.innerHTML = v;
        else if (k.slice(0, 2) === "on" && typeof v === "function") {
          node.addEventListener(k.slice(2).toLowerCase(), v);
        } else node.setAttribute(k, v === true ? "" : String(v));
      });
    }
    (Array.isArray(children) ? children : children != null ? [children] : []).forEach(function (c) {
      if (c == null || c === false) return;
      node.appendChild(c.nodeType ? c : document.createTextNode(String(c)));
    });
    return node;
  };

  PS.escape = function (s) {
    return String(s == null ? "" : s).replace(/[&<>"']/g, function (c) {
      return { "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[c];
    });
  };

  PS.reducedMotion = function () {
    return window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  };

  // First-reveal fade/rise (<=200ms). No-op under prefers-reduced-motion.
  PS.reveal = function (node) {
    if (PS.reducedMotion()) return;
    node.classList.add("ps-reveal");
    requestAnimationFrame(function () {
      requestAnimationFrame(function () {
        node.classList.add("is-in");
      });
    });
  };

  PS.register = function (name, fn) {
    PS.components[name] = fn;
  };

  /* ---- Error + loading placeholders ----------------------------------- */
  function setState(el, cls, msg) {
    el.innerHTML = "";
    el.appendChild(PS.h("div.ps-state." + cls, { role: "status" }, msg));
  }

  /* ---- Mount ---------------------------------------------------------- */
  PS.mount = function (root) {
    root = root || document;
    var nodes = root.querySelectorAll("[data-ps-app]");
    Array.prototype.forEach.call(nodes, function (el) {
      if (el.__psMounted) return;
      el.__psMounted = true;
      var type = el.getAttribute("data-ps-app");
      var comp = PS.components[type];
      if (!comp) {
        setState(el, "ps-state--error", 'Unknown component "' + type + '".');
        return;
      }
      if (!el.getAttribute("data-ps-quiet")) setState(el, "ps-state--loading", "Loading…");
      try {
        Promise.resolve(comp(el)).catch(function (err) {
          console.error(err);
          setState(el, "ps-state--error", "Could not load this section.");
        });
      } catch (err) {
        console.error(err);
        setState(el, "ps-state--error", "Could not load this section.");
      }
    });
  };

  /* ---- SEO: JSON-LD structured data ---------------------------------- */
  PS.injectJsonLd = function (obj) {
    var s = document.createElement("script");
    s.type = "application/ld+json";
    s.textContent = JSON.stringify(obj);
    document.head.appendChild(s);
  };

  PS.injectSeo = async function (root) {
    root = root || document;
    var origin = location.origin && location.origin !== "null" ? location.origin : "";
    // WebSite — emitted on the home page (identified by a carousel mount).
    if (root.querySelector('[data-ps-app="carousel"]')) {
      PS.injectJsonLd({
        "@context": "https://schema.org", "@type": "WebSite",
        name: "Physics Solved", url: origin || undefined,
        description: "Interactive physics and chemistry study tools: equation finders, formula sheets, FRQ practice, a periodic table, and calculators."
      });
    }
    // LearningResource — one per course mount (equation-finder with data-course).
    var courseMounts = root.querySelectorAll('[data-ps-app="equation-finder"][data-course]');
    if (courseMounts.length) {
      try {
        var reg = await PS.getRegistry();
        var byId = {};
        (reg.subjects || []).forEach(function (s) {
          (s.courses || []).forEach(function (c) { byId[c.id] = c; });
        });
        Array.prototype.forEach.call(courseMounts, function (m) {
          var c = byId[m.getAttribute("data-course")];
          if (!c) return;
          PS.injectJsonLd({
            "@context": "https://schema.org", "@type": "LearningResource",
            name: c.label + " — equation finder & study tools",
            educationalLevel: c.eyebrow || "High school",
            about: c.blurb || c.label,
            isAccessibleForFree: true,
            url: c.url ? (origin + c.url) : undefined,
            learningResourceType: ["Reference", "Practice problems"]
          });
        });
      } catch (e) { /* non-fatal */ }
    }
    // Person + CreativeWork list — on the portfolio page.
    if (root.querySelector('[data-ps-app="portfolio"]')) {
      try {
        var pf = await PS.fetchJSON("portfolio.json");
        PS.injectJsonLd({
          "@context": "https://schema.org", "@type": "Person",
          name: pf.owner || "Physics Solved",
          url: origin || undefined,
          description: pf.intro || undefined
        });
        var projects = (pf.projects || []).map(function (p) {
          return { "@type": "CreativeWork", name: p.title, dateCreated: p.year ? String(p.year) : undefined,
            abstract: p.summary, keywords: (p.tags || []).join(", ") || undefined };
        });
        if (projects.length) {
          PS.injectJsonLd({
            "@context": "https://schema.org", "@type": "ItemList",
            itemListElement: projects.map(function (w, i) { return { "@type": "ListItem", position: i + 1, item: w }; })
          });
        }
      } catch (e) { /* non-fatal */ }
    }
  };

  function boot() {
    PS.mount();
    PS.injectSeo();
  }
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", boot);
  } else {
    // Defer to a macrotask so the rest of a concatenated bundle registers its
    // components BEFORE we scan the page (core.js runs before them in the file).
    setTimeout(boot, 0);
  }
})();

/* --- src/js/grading-adapter.js --- */
/* Physics Solved — FRQ grading adapter.
 * All direct Anthropic API calls have been removed. Grading is pluggable:
 * with no provider set, the UI runs in self-check mode (reveal model answers +
 * self-assessment). To enable AI feedback later, set PS.grading.provider to an
 * object with an { endpoint } that points at a serverless proxy (e.g. a
 * Cloudflare Worker). No other file needs to change — see worker/README.md.
 */
(function () {
  "use strict";
  var PS = (window.PS = window.PS || {});

  PS.grading = {
    // provider: { endpoint: "https://your-worker.example.workers.dev/grade" }
    provider: null,

    /**
     * Grade a question given the student's per-part answers.
     * @param {object} question  the FRQ object (id, parts, ...)
     * @param {object} answers   map of part label -> student text
     * @returns {Promise<object>} result shape consumed by the FRQ UI:
     *   self-check:  { mode: "self-check" }
     *   graded:      { mode: "graded", parts: [{ label, score, max, feedback }],
     *                  score, max }
     */
    async grade(question, answers) {
      if (!this.provider || !this.provider.endpoint) {
        return { mode: "self-check" };
      }
      // Future: POST { question, answers } to the proxy and return its JSON.
      // The proxy holds the API key server-side; the browser never sees it.
      var res = await fetch(this.provider.endpoint, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ question: question, answers: answers })
      });
      if (!res.ok) throw new Error("Grading proxy error " + res.status);
      return res.json(); // expected: { mode: "graded", parts: [...], score, max }
    }
  };
})();

/* --- src/js/components/carousel.js --- */
/* Physics Solved — course carousel.
 * <div data-ps-app="carousel" data-subject="physics"></div>
 * Renders one card per course in the given subject, straight from registry.json.
 * Scroll-snap track, prev/next arrows, edge-fade masks, keyboard arrows.
 */
(function () {
  "use strict";
  var PS = window.PS;

  function card(course) {
    var live = course.status === "live" && course.url;
    var accent = course.accent || "#2547d0";
    var cover = PS.h("div.ps-course-cover", {
      style: "--ps-accent:" + accent,
      "aria-hidden": "true"
    }, PS.h("span.ps-course-cover-mark", {}, initials(course.label)));

    var body = PS.h("div.ps-course-body", {}, [
      course.eyebrow ? PS.h("div.ps-eyebrow", {}, course.eyebrow) : null,
      PS.h("h3.ps-course-title", {}, course.label),
      course.blurb ? PS.h("p.ps-course-blurb", {}, course.blurb) : null,
      course.status === "coming-soon"
        ? PS.h("span.ps-badge.ps-badge--muted", {}, "Coming soon")
        : PS.h("span.ps-course-cta", { "aria-hidden": "true" }, "Open course →")
    ]);

    if (live) {
      return PS.h("a.ps-card.ps-course-card", {
        href: course.url,
        style: "--ps-accent:" + accent,
        "aria-label": course.label + (course.eyebrow ? " — " + course.eyebrow : "")
      }, [cover, body]);
    }
    return PS.h("div.ps-card.ps-course-card.is-coming", {
      style: "--ps-accent:" + accent,
      "aria-disabled": "true"
    }, [cover, body]);
  }

  function initials(label) {
    return String(label || "")
      .replace(/[^A-Za-z0-9 ]/g, "")
      .split(/\s+/)
      .slice(0, 2)
      .map(function (w) { return w[0]; })
      .join("")
      .toUpperCase();
  }

  PS.register("carousel", async function (el) {
    var subjectId = el.getAttribute("data-subject") || "physics";
    var reg = await PS.getRegistry();
    var subject = (reg.subjects || []).find(function (s) { return s.id === subjectId; });
    el.innerHTML = "";
    if (!subject || !subject.courses || !subject.courses.length) {
      el.appendChild(PS.h("div.ps-state", {}, "No courses found for “" + subjectId + "”."));
      return;
    }

    var track = PS.h("div.ps-carousel-track", { role: "list", tabindex: "0",
      "aria-label": subject.label + " courses" });
    subject.courses.forEach(function (c) {
      var wrap = PS.h("div.ps-carousel-item", { role: "listitem" }, card(c));
      track.appendChild(wrap);
    });

    var prev = PS.h("button.ps-carousel-arrow.ps-carousel-arrow--prev", {
      type: "button", "aria-label": "Previous courses" }, arrow("left"));
    var next = PS.h("button.ps-carousel-arrow.ps-carousel-arrow--next", {
      type: "button", "aria-label": "Next courses" }, arrow("right"));

    var viewport = PS.h("div.ps-carousel-viewport", {}, track);
    var carousel = PS.h("div.ps-carousel", {}, [prev, viewport, next]);
    el.appendChild(carousel);

    function step() {
      var item = track.querySelector(".ps-carousel-item");
      return item ? item.getBoundingClientRect().width + 16 : 280;
    }
    function scrollBy(dir) {
      track.scrollBy({ left: dir * step(), behavior: PS.reducedMotion() ? "auto" : "smooth" });
    }
    prev.addEventListener("click", function () { scrollBy(-1); });
    next.addEventListener("click", function () { scrollBy(1); });
    track.addEventListener("keydown", function (e) {
      if (e.key === "ArrowRight") { e.preventDefault(); scrollBy(1); }
      else if (e.key === "ArrowLeft") { e.preventDefault(); scrollBy(-1); }
    });

    function update() {
      var maxScroll = track.scrollWidth - track.clientWidth - 1;
      var x = track.scrollLeft;
      prev.disabled = x <= 0;
      next.disabled = x >= maxScroll;
      carousel.classList.toggle("has-fade-start", x > 4);
      carousel.classList.toggle("has-fade-end", x < maxScroll - 4);
    }
    track.addEventListener("scroll", function () {
      window.requestAnimationFrame(update);
    });
    window.addEventListener("resize", update);
    update();
    PS.reveal(carousel);
  });

  function arrow(dir) {
    var svg = document.createElementNS("http://www.w3.org/2000/svg", "svg");
    svg.setAttribute("viewBox", "0 0 24 24");
    svg.setAttribute("width", "20");
    svg.setAttribute("height", "20");
    svg.setAttribute("aria-hidden", "true");
    var path = document.createElementNS("http://www.w3.org/2000/svg", "path");
    path.setAttribute("d", dir === "left" ? "M15 5l-7 7 7 7" : "M9 5l7 7-7 7");
    path.setAttribute("fill", "none");
    path.setAttribute("stroke", "currentColor");
    path.setAttribute("stroke-width", "2");
    path.setAttribute("stroke-linecap", "round");
    path.setAttribute("stroke-linejoin", "round");
    svg.appendChild(path);
    return svg;
  }
})();

/* --- src/js/components/equation-finder.js --- */
/* Physics Solved — equation finder.
 * <div data-ps-app="equation-finder" data-course="ap-physics-1"></div>
 * Accordion of units; check the variables you know and the equations that use
 * them are revealed. Match mode is "any" (>=1 checked) or "all" (every use
 * checked). data-course selects data/equations/<course>.json.
 */
(function () {
  "use strict";
  var PS = window.PS;

  PS.register("equation-finder", async function (el) {
    var course = el.getAttribute("data-course");
    if (!course) {
      el.innerHTML = "";
      el.appendChild(PS.h("div.ps-state.ps-state--error", {},
        'equation-finder needs a data-course attribute (e.g. "ap-physics-1").'));
      return;
    }
    var data = await PS.fetchJSON("equations/" + course + ".json");
    el.innerHTML = "";

    var mode = "any";
    var units = [];

    var head = PS.h("div.ps-ef-head", {}, [
      PS.h("div.ps-ef-head-text", {}, [
        PS.h("h2.ps-h3", {}, "Equation Finder"),
        PS.h("p.ps-muted", {}, "Check the variables you have — matching equations appear.")
      ]),
      matchToggle()
    ]);
    el.appendChild(head);
    if (data.note) el.appendChild(PS.h("p.ps-ef-note", {}, data.note));

    var acc = PS.h("div.ps-accordion", {});
    (data.units || []).forEach(function (unit, i) {
      acc.appendChild(renderUnit(unit, i));
    });
    el.appendChild(acc);
    PS.reveal(acc);

    function matchToggle() {
      var group = PS.h("div.ps-segment", { role: "group", "aria-label": "Match mode" });
      ["any", "all"].forEach(function (m) {
        var btn = PS.h("button.ps-segment-btn", {
          type: "button",
          "aria-pressed": m === mode ? "true" : "false",
          "data-mode": m
        }, m === "any" ? "Match any" : "Match all");
        btn.addEventListener("click", function () {
          mode = m;
          group.querySelectorAll(".ps-segment-btn").forEach(function (b) {
            b.setAttribute("aria-pressed", b.getAttribute("data-mode") === mode ? "true" : "false");
          });
          units.forEach(function (u) { u.apply(); });
        });
        group.appendChild(btn);
      });
      return group;
    }

    function renderUnit(unit, index) {
      var checked = Object.create(null);
      var vars = unit.variables || [];
      var eqs = unit.equations || [];
      var open = index === 0;

      var count = PS.h("span.ps-ef-count", { "aria-live": "polite" }, "");
      var caret = PS.h("span.ps-accordion-caret", { "aria-hidden": "true" });
      var panelId = "ps-ef-" + course + "-" + index;
      var btn = PS.h("button.ps-accordion-head", {
        type: "button",
        "aria-expanded": open ? "true" : "false",
        "aria-controls": panelId
      }, [
        PS.h("span.ps-accordion-title", {}, [
          unit.title,
          PS.h("span.ps-accordion-meta", {}, " · " + vars.length + " variable" + (vars.length === 1 ? "" : "s"))
        ]),
        count,
        caret
      ]);

      var grid = PS.h("div.ps-var-grid", {});
      vars.forEach(function (v) {
        var id = panelId + "-v-" + slug(v.sym);
        var input = PS.h("input", { type: "checkbox", id: id, "data-sym": v.sym });
        input.addEventListener("change", function () {
          if (input.checked) checked[v.sym] = true; else delete checked[v.sym];
          apply();
        });
        var label = PS.h("label.ps-var", { for: id, title: v.name + (v.note ? " — " + v.note : "") }, [
          input,
          PS.h("span.ps-var-sym.ps-mono", {}, v.sym),
          PS.h("span.ps-var-name", {}, v.name)
        ]);
        grid.appendChild(label);
      });

      var list = PS.h("div.ps-eq-list", {});
      var rows = eqs.map(function (eq) {
        var row = PS.h("div.ps-eq", {}, [
          PS.h("span.ps-eq-name", {}, eq.name),
          PS.h("span.ps-eq-expr.ps-mono", {}, eq.expr)
        ]);
        return { node: row, uses: eq.uses || [] };
      });
      rows.forEach(function (r) { list.appendChild(r.node); });

      var panel = PS.h("div.ps-accordion-panel", { id: panelId, hidden: !open }, [
        vars.length ? grid : null,
        list
      ]);

      btn.addEventListener("click", function () {
        var isOpen = btn.getAttribute("aria-expanded") === "true";
        btn.setAttribute("aria-expanded", isOpen ? "false" : "true");
        panel.hidden = isOpen;
      });

      function apply() {
        var keys = Object.keys(checked);
        var active = keys.length > 0;
        var shown = 0;
        rows.forEach(function (r) {
          var match;
          if (!active) match = true;
          else if (mode === "any") match = r.uses.some(function (u) { return checked[u]; });
          else match = r.uses.length > 0 && r.uses.every(function (u) { return checked[u]; });
          r.node.classList.toggle("is-hidden", !match);
          if (match) shown++;
        });
        count.textContent = active ? shown + " match" + (shown === 1 ? "" : "es") : "";
      }
      apply();
      units.push({ apply: apply });
      return PS.h("div.ps-accordion-item", {}, [btn, panel]);
    }
  });

  function slug(s) {
    return String(s).replace(/[^A-Za-z0-9]/g, function (c) { return "_" + c.charCodeAt(0); });
  }
})();

/* --- src/js/components/formula-library.js --- */
/* Physics Solved — formula sheet library.
 * <div data-ps-app="formula-library"></div>
 * Tab pills are built from every sheet declared on the physics courses in
 * registry.json (so tabs and courses can never disagree). Sheets load lazily.
 * Tablist semantics + arrow-key navigation. Print opens a clean sheet-only page.
 */
(function () {
  "use strict";
  var PS = window.PS;

  PS.register("formula-library", async function (el) {
    var subjectId = el.getAttribute("data-subject") || "physics";
    var reg = await PS.getRegistry();
    var subject = (reg.subjects || []).find(function (s) { return s.id === subjectId; });
    el.innerHTML = "";

    // Flatten sheets across the subject's courses -> tab list.
    var tabs = [];
    (subject ? subject.courses : []).forEach(function (course) {
      (course.sheets || []).forEach(function (sh) {
        tabs.push({ id: sh.id, label: sh.label, file: sh.file, accent: course.accent });
      });
    });
    if (!tabs.length) {
      el.appendChild(PS.h("div.ps-state", {}, "No formula sheets are configured."));
      return;
    }

    var tablist = PS.h("div.ps-tabs", { role: "tablist", "aria-label": "Formula sheets" });
    var panel = PS.h("div.ps-tabpanel", { role: "tabpanel", tabindex: "0", "aria-live": "polite" });
    var buttons = [];

    tabs.forEach(function (tab, i) {
      var btn = PS.h("button.ps-tab", {
        type: "button",
        role: "tab",
        id: "ps-tab-" + tab.id,
        "aria-controls": panel.id || "ps-fl-panel",
        "aria-selected": i === 0 ? "true" : "false",
        tabindex: i === 0 ? "0" : "-1",
        style: "--ps-accent:" + (tab.accent || "#2547d0")
      }, tab.label);
      btn.addEventListener("click", function () { select(i); });
      buttons.push(btn);
      tablist.appendChild(btn);
    });
    panel.id = "ps-fl-panel";
    tablist.addEventListener("keydown", onKeydown);

    el.appendChild(tablist);
    el.appendChild(panel);

    var current = -1;
    var loaded = Object.create(null);
    select(0);

    function onKeydown(e) {
      var i = buttons.indexOf(document.activeElement);
      if (i < 0) return;
      var n = buttons.length, j = i;
      if (e.key === "ArrowRight") j = (i + 1) % n;
      else if (e.key === "ArrowLeft") j = (i - 1 + n) % n;
      else if (e.key === "Home") j = 0;
      else if (e.key === "End") j = n - 1;
      else return;
      e.preventDefault();
      buttons[j].focus();
      select(j);
    }

    function select(i) {
      if (i === current) return;
      current = i;
      buttons.forEach(function (b, k) {
        var on = k === i;
        b.setAttribute("aria-selected", on ? "true" : "false");
        b.tabIndex = on ? 0 : -1;
      });
      panel.setAttribute("aria-labelledby", buttons[i].id);
      renderSheet(tabs[i]);
    }

    async function renderSheet(tab) {
      panel.innerHTML = "";
      panel.appendChild(PS.h("div.ps-state.ps-state--loading", {}, "Loading sheet…"));
      var data;
      try {
        data = loaded[tab.id] || (loaded[tab.id] = await PS.fetchJSON(tab.file));
      } catch (err) {
        panel.innerHTML = "";
        panel.appendChild(PS.h("div.ps-state.ps-state--error", {}, "Could not load this sheet."));
        return;
      }
      panel.innerHTML = "";
      panel.appendChild(sheetNode(data, tab.accent));
    }
  });

  function sheetNode(data, accent) {
    var sheet = PS.h("div.ps-sheet", { style: "--ps-accent:" + (accent || "#2547d0") });

    var header = PS.h("div.ps-sheet-head", {}, [
      PS.h("div", {}, [
        PS.h("h3.ps-sheet-title", {}, data.title || "Formula Sheet"),
        data.tagline ? PS.h("p.ps-sheet-tagline.ps-muted", {}, data.tagline) : null
      ]),
      printButton(sheet, data.title || "Formula Sheet")
    ]);
    sheet.appendChild(header);

    if (data.constants && data.constants.length) {
      var strip = PS.h("div.ps-constants", { "aria-label": "Constants" });
      data.constants.forEach(function (c) {
        strip.appendChild(PS.h("span.ps-constant", {}, [
          PS.h("span.ps-constant-sym.ps-mono", {}, c.sym),
          PS.h("span.ps-constant-val.ps-mono", {}, c.value)
        ]));
      });
      sheet.appendChild(strip);
    }

    var grid = PS.h("div.ps-sheet-grid");
    (data.categories || []).forEach(function (cat) {
      var card = PS.h("div.ps-card.ps-sheet-card", {}, [
        PS.h("h4.ps-sheet-cat", {}, cat.title)
      ]);
      var rows = PS.h("div.ps-sheet-rows");
      (cat.rows || []).forEach(function (row) {
        rows.appendChild(PS.h("div.ps-sheet-row", {}, [
          PS.h("span.ps-sheet-row-name", {}, row.name),
          PS.h("span.ps-sheet-row-expr.ps-mono", {}, row.expr)
        ]));
      });
      card.appendChild(rows);
      grid.appendChild(card);
    });
    sheet.appendChild(grid);
    return sheet;
  }

  function printButton(sheet, title) {
    var btn = PS.h("button.ps-btn.ps-btn--dark", { type: "button" }, "Print / Save PDF");
    btn.addEventListener("click", function () { printSheet(sheet, title); });
    return btn;
  }

  // Print just the sheet in a clean popup, styled by the CDN stylesheet, so the
  // surrounding Squarespace page is never touched (no body/html rules needed).
  function printSheet(sheet, title) {
    var win = window.open("", "_blank", "width=900,height=1000");
    if (!win) { window.print(); return; } // popup blocked -> best effort
    // Absolute URL so it resolves inside the about:blank popup (base may be relative).
    var css = new URL(PS.base + "dist/physics-solved.min.css", document.baseURI).href;
    win.document.open();
    win.document.write(
      '<!doctype html><html><head><meta charset="utf-8">' +
      '<title>' + PS.escape(title) + '</title>' +
      '<link rel="stylesheet" href="' + PS.escape(css) + '">' +
      '</head><body class="ps-print-body"><div class="ps-root ps-print-doc">' +
      sheet.outerHTML + "</div></body></html>"
    );
    win.document.close();
    var go = function () { win.focus(); win.print(); };
    // Give the stylesheet a moment to load, then print.
    if (win.document.readyState === "complete") setTimeout(go, 250);
    else win.addEventListener("load", function () { setTimeout(go, 150); });
  }
})();

/* --- src/js/components/frq.js --- */
/* Physics Solved — FRQ practice.
 * <div data-ps-app="frq" data-subject="physics"></div>
 *   data-subject   single subject id (default "physics"); course pages use this.
 *   data-subjects  comma list (e.g. "physics,chemistry") -> subject switcher tabs.
 *   data-grader-endpoint  optional serverless proxy URL; presence enables AI
 *                  grading (PS.grading.provider). Off by default. No key client-side.
 *
 * Filters, badges, and the FRQ file all come from registry.json (per-subject
 * frqFile). Progress (self-check ratings) persists in localStorage under
 * ps.frq.v1.*. There are NO direct API calls unless a grader endpoint is set.
 */
(function () {
  "use strict";
  var PS = window.PS;
  var PKEY = "ps.frq.v1.";

  function loadProg(qid) {
    try { return JSON.parse(localStorage.getItem(PKEY + qid)) || null; } catch (e) { return null; }
  }
  function saveProg(qid, obj) {
    try { localStorage.setItem(PKEY + qid, JSON.stringify(obj)); } catch (e) {}
  }
  function statusOf(q) {
    var p = loadProg(q.id);
    if (!p || !p.parts) return "none";
    var rated = Object.keys(p.parts);
    if (!rated.length) return "none";
    var parts = q.parts || [];
    var allGot = parts.length > 0 && parts.every(function (_, i) { return p.parts[i] === "got"; });
    return allGot ? "mastered" : "attempted";
  }

  PS.register("frq", async function (el) {
    var reg = await PS.getRegistry();

    var endpoint = el.getAttribute("data-grader-endpoint");
    if (endpoint && PS.grading) PS.grading.provider = { endpoint: endpoint };

    var ids = (el.getAttribute("data-subjects") || el.getAttribute("data-subject") || "physics")
      .split(",").map(function (s) { return s.trim(); }).filter(Boolean);
    var subjects = ids.map(function (id) {
      return (reg.subjects || []).find(function (s) { return s.id === id; });
    }).filter(Boolean);
    if (!subjects.length) {
      el.innerHTML = "";
      el.appendChild(PS.h("div.ps-state.ps-state--error", {}, "No FRQ subjects configured."));
      return;
    }

    el.innerHTML = "";
    var courseById = {};
    var questions = [];
    var filter = "all", diffFilter = 0, selectedId = null, curSubject = null;

    /* ---- Skeleton --------------------------------------------------- */
    var subjectTabs = PS.h("div.ps-frq-subjects", { role: "tablist", "aria-label": "Subject" });
    var pills = PS.h("div.ps-pills", { role: "tablist", "aria-label": "Filter questions by course" });
    var diffPills = PS.h("div.ps-pills.ps-frq-difffilter", { role: "group", "aria-label": "Filter by difficulty" });
    var randomBtn = PS.h("button.ps-btn.ps-btn--ghost", { type: "button" }, "🎲 Random question");
    randomBtn.addEventListener("click", pickRandom);
    var controls = PS.h("div.ps-frq-controls", {}, [pills, PS.h("div.ps-frq-controls-right", {}, [diffPills, randomBtn])]);

    var progress = PS.h("div.ps-frq-progress", { role: "status", "aria-live": "polite" });
    var listWrap = PS.h("div.ps-frq-list", { role: "list", "aria-label": "Questions" });
    var mobileSelect = PS.h("select.ps-frq-select", { "aria-label": "Choose a question" });
    mobileSelect.addEventListener("change", function () { if (mobileSelect.value) selectQuestion(mobileSelect.value); });
    var listCol = PS.h("div.ps-frq-listcol", {}, [mobileSelect, progress, listWrap]);
    var viewer = PS.h("div.ps-frq-viewer", { role: "region", "aria-live": "polite", "aria-label": "Question viewer" });
    var panes = PS.h("div.ps-frq-panes", {}, [listCol, viewer]);

    if (subjects.length > 1) {
      subjects.forEach(function (s) {
        var btn = PS.h("button.ps-frq-subject", { type: "button", role: "tab",
          "aria-selected": "false", style: s.accentTab }, s.label);
        btn.addEventListener("click", function () { loadSubject(s); });
        subjectTabs.appendChild(btn);
      });
      el.appendChild(subjectTabs);
    }
    el.appendChild(controls);
    el.appendChild(panes);
    PS.reveal(panes);

    // Difficulty filter pills
    [{ v: 0, label: "Any level" }, { v: 1, label: "Easy" }, { v: 2, label: "Medium" }, { v: 3, label: "Hard" }]
      .forEach(function (d) {
        var b = PS.h("button.ps-pill", { type: "button", "aria-pressed": d.v === 0 ? "true" : "false", "data-diff": d.v }, d.label);
        b.addEventListener("click", function () {
          diffFilter = d.v;
          diffPills.querySelectorAll(".ps-pill").forEach(function (x) {
            x.setAttribute("aria-pressed", String(+x.getAttribute("data-diff") === diffFilter));
          });
          renderList();
        });
        diffPills.appendChild(b);
      });

    await loadSubject(subjects[0]);

    /* ---- Subject loading -------------------------------------------- */
    async function loadSubject(subject) {
      curSubject = subject;
      subjectTabs.querySelectorAll(".ps-frq-subject").forEach(function (b) {
        b.setAttribute("aria-selected", String(b.textContent === subject.label));
      });
      courseById = {};
      subject.courses.forEach(function (c) { courseById[c.id] = c; });
      var frqFile = subject.frqFile || ("frq/" + subject.id + ".json");
      var data;
      try { data = await PS.fetchJSON(frqFile); }
      catch (e) { questions = []; }
      questions = (data && data.questions) || [];
      filter = "all"; selectedId = null;
      renderCoursePills();
      renderList();
      renderProgress();
      showEmpty();
    }

    function renderCoursePills() {
      pills.innerHTML = "";
      var frqCourses = curSubject.courses.filter(function (c) { return (c.features || []).indexOf("frq") !== -1; });
      var defs = [{ id: "all", label: "All" }].concat(frqCourses.map(function (c) {
        return { id: c.id, label: c.label, accent: c.accent };
      }));
      defs.forEach(function (p) {
        var btn = PS.h("button.ps-pill", { type: "button", role: "tab",
          "aria-selected": p.id === filter ? "true" : "false",
          "data-course": p.id, style: p.accent ? "--ps-accent:" + p.accent : null }, p.label);
        btn.addEventListener("click", function () { setFilter(p.id); });
        pills.appendChild(btn);
      });
    }

    /* ---- List ------------------------------------------------------- */
    function visibleQuestions() {
      return questions.filter(function (q) {
        if (filter !== "all" && q.courseId !== filter) return false;
        if (diffFilter && (q.difficulty || 0) !== diffFilter) return false;
        return true;
      });
    }

    function setFilter(id) {
      filter = id;
      pills.querySelectorAll(".ps-pill").forEach(function (b) {
        b.setAttribute("aria-selected", String(b.getAttribute("data-course") === id));
      });
      renderList();
      if (!visibleQuestions().some(function (q) { return q.id === selectedId; })) showEmpty();
    }

    function diffDots(d) {
      d = Math.max(0, Math.min(3, d || 0));
      var wrap = PS.h("span.ps-frq-diff", { title: "Difficulty " + d + "/3", "aria-label": "Difficulty " + d + " of 3" });
      for (var i = 1; i <= 3; i++) wrap.appendChild(PS.h("span.ps-frq-dot" + (i <= d ? ".is-on" : ""), {}));
      return wrap;
    }

    function statusBadge(status) {
      if (status === "mastered") return PS.h("span.ps-frq-status.is-mastered", { title: "All parts self-rated correct" }, "✓ Mastered");
      if (status === "attempted") return PS.h("span.ps-frq-status.is-attempted", { title: "Previously attempted" }, "Attempted");
      return null;
    }

    function renderList() {
      listWrap.innerHTML = "";
      mobileSelect.innerHTML = "";
      mobileSelect.appendChild(PS.h("option", { value: "" }, "Select a question…"));
      var vis = visibleQuestions();
      if (!vis.length) {
        listWrap.appendChild(PS.h("div.ps-state", {}, "No questions in this filter yet."));
        return;
      }
      vis.forEach(function (q) {
        var course = courseById[q.courseId] || {};
        var status = statusOf(q);
        var item = PS.h("button.ps-frq-item", { type: "button", role: "listitem",
          "data-id": q.id, "aria-current": q.id === selectedId ? "true" : "false" }, [
          PS.h("span.ps-frq-item-top", {}, [
            PS.h("span.ps-badge", { style: "--ps-accent:" + (course.accent || "#2547d0") }, course.label || q.courseId),
            diffDots(q.difficulty),
            statusBadge(status)
          ]),
          PS.h("span.ps-frq-item-unit", {}, q.unit || ""),
          PS.h("span.ps-frq-item-title", {}, q.title || "Untitled")
        ]);
        item.addEventListener("click", function () { selectQuestion(q.id); });
        listWrap.appendChild(item);
        mobileSelect.appendChild(PS.h("option", { value: q.id },
          (course.label ? course.label + " — " : "") + (q.title || "Untitled")));
      });
      if (selectedId) mobileSelect.value = selectedId;
    }

    function renderProgress() {
      var frqCourses = curSubject.courses.filter(function (c) { return (c.features || []).indexOf("frq") !== -1; });
      var bits = [];
      frqCourses.forEach(function (c) {
        var qs = questions.filter(function (q) { return q.courseId === c.id; });
        if (!qs.length) return;
        var att = 0, mas = 0;
        qs.forEach(function (q) { var s = statusOf(q); if (s === "attempted") att++; else if (s === "mastered") { att++; mas++; } });
        bits.push(c.label + ": " + mas + "★ · " + att + "/" + qs.length + " tried");
      });
      progress.textContent = bits.length ? bits.join("   ") : "";
    }

    function pickRandom() {
      var vis = visibleQuestions();
      if (!vis.length) return;
      selectQuestion(vis[Math.floor(Math.random() * vis.length)].id);
    }

    function markActive(id) {
      listWrap.querySelectorAll(".ps-frq-item").forEach(function (b) {
        b.setAttribute("aria-current", String(b.getAttribute("data-id") === id));
      });
      mobileSelect.value = id || "";
    }

    function showEmpty() {
      selectedId = null;
      markActive(null);
      viewer.innerHTML = "";
      viewer.appendChild(PS.h("div.ps-frq-empty", {}, [
        PS.h("div.ps-frq-empty-icon", { "aria-hidden": "true" }, "📝"),
        PS.h("p.ps-frq-empty-title", {}, "Pick a question to get started"),
        PS.h("p.ps-muted", {}, "Select a question from the list — or try a random one.")
      ]));
    }

    function selectQuestion(id) {
      var q = questions.find(function (x) { return x.id === id; });
      if (!q) return;
      selectedId = id;
      markActive(id);
      renderQuestion(q);
    }

    /* ---- Viewer ----------------------------------------------------- */
    function renderQuestion(q) {
      var course = courseById[q.courseId] || {};
      viewer.innerHTML = "";
      viewer.appendChild(PS.h("div.ps-frq-qhead", {}, [
        PS.h("span.ps-badge", { style: "--ps-accent:" + (course.accent || "#2547d0") }, course.label || q.courseId),
        q.unit ? PS.h("span.ps-frq-qunit", {}, q.unit) : null,
        diffDots(q.difficulty),
        PS.h("h3.ps-frq-qtitle", {}, q.title || "Untitled")
      ]));
      if (q.scenario) viewer.appendChild(PS.h("p.ps-frq-scenario", {}, q.scenario));

      var partNodes = [];
      (q.parts || []).forEach(function (part, i) {
        var taId = "ps-frq-" + q.id + "-p" + i;
        var ta = PS.h("textarea.ps-frq-answer", { id: taId, rows: "3", placeholder: "Your answer…" });
        var reveal = PS.h("div.ps-frq-reveal", { hidden: true });
        viewer.appendChild(PS.h("div.ps-frq-part", {}, [
          PS.h("label.ps-frq-part-label", { for: taId }, [
            PS.h("span.ps-frq-part-tag", {}, part.label || "Part " + (i + 1)),
            part.points ? PS.h("span.ps-frq-points", {}, part.points + " pt" + (part.points === 1 ? "" : "s")) : null
          ]),
          part.text ? PS.h("p.ps-frq-part-text", {}, part.text) : null,
          ta, reveal
        ]));
        partNodes.push({ part: part, ta: ta, reveal: reveal, points: part.points || 1 });
      });

      var checkBtn = PS.h("button.ps-btn", { type: "button" }, "Check my work");
      var summary = PS.h("div.ps-frq-summary", { role: "status", "aria-live": "polite", hidden: true });
      viewer.appendChild(PS.h("div.ps-frq-actions", {}, [checkBtn, summary]));

      checkBtn.addEventListener("click", async function () {
        var answers = {};
        partNodes.forEach(function (p, i) { answers[p.part.label || "Part " + (i + 1)] = p.ta.value; });
        checkBtn.disabled = true;
        checkBtn.textContent = "Checking…";
        var result;
        try { result = await PS.grading.grade(q, answers); }
        catch (err) {
          console.error(err);
          checkBtn.disabled = false;
          checkBtn.textContent = "Check my work";
          summary.hidden = false;
          summary.textContent = "Grading service unavailable — showing model answers.";
          renderSelfCheck();
          return;
        }
        checkBtn.textContent = "Answers revealed";
        if (result && result.mode === "graded" && result.parts) renderGraded(result);
        else renderSelfCheck();
      });

      function renderSelfCheck() {
        var saved = loadProg(q.id);
        var state = (saved && saved.parts) ? Object.assign({}, saved.parts) : {};
        partNodes.forEach(function (p, i) {
          p.reveal.hidden = false;
          p.reveal.innerHTML = "";
          if (p.part.modelAnswer) {
            p.reveal.appendChild(PS.h("div.ps-frq-model", {}, [
              PS.h("span.ps-frq-model-tag", {}, "Model answer"),
              PS.h("span.ps-frq-model-text.ps-mono", {}, p.part.modelAnswer)
            ]));
          }
          var seg = PS.h("div.ps-segment.ps-frq-selfassess", { role: "group",
            "aria-label": "How did you do on " + (p.part.label || "this part") + "?" });
          [["got", "Got it"], ["partial", "Partially"], ["missed", "Missed"]].forEach(function (opt) {
            var b = PS.h("button.ps-segment-btn", { type: "button", "data-v": opt[0],
              "aria-pressed": String(state[i] === opt[0]) }, opt[1]);
            b.addEventListener("click", function () {
              state[i] = opt[0];
              seg.querySelectorAll(".ps-segment-btn").forEach(function (x) {
                x.setAttribute("aria-pressed", String(x.getAttribute("data-v") === opt[0]));
              });
              saveProg(q.id, { parts: state, ts: Date.now() });
              updateSummary();
              renderList();
              renderProgress();
            });
            seg.appendChild(b);
          });
          p.reveal.appendChild(seg);
        });

        function updateSummary() {
          var total = 0, earned = 0, answered = 0;
          partNodes.forEach(function (p, i) {
            total += p.points;
            if (state[i]) { answered++; earned += state[i] === "got" ? p.points : state[i] === "partial" ? p.points / 2 : 0; }
          });
          summary.hidden = false;
          summary.textContent = !answered ? "Rate each part to record your progress."
            : "Self-score: " + round(earned) + " / " + total + " pts (" + answered + " of " + partNodes.length + " parts rated)";
        }
        updateSummary();
      }

      function renderGraded(result) {
        partNodes.forEach(function (p, i) {
          var fb = result.parts[i] || {};
          p.reveal.hidden = false;
          p.reveal.innerHTML = "";
          p.reveal.appendChild(PS.h("div.ps-frq-model", {}, [
            PS.h("span.ps-frq-model-tag", {}, "Feedback" +
              (fb.score != null ? " · " + fb.score + "/" + (fb.max != null ? fb.max : p.points) : "")),
            PS.h("span.ps-frq-model-text", {}, fb.feedback || "—")
          ]));
        });
        summary.hidden = false;
        summary.textContent = result.score != null
          ? "Score: " + result.score + " / " + (result.max != null ? result.max : "") + " pts" : "Graded.";
      }
    }
  });

  function round(n) { return Math.round(n * 10) / 10; }
})();

/* --- src/js/components/simulator-kinematics.js --- */
/* Physics Solved — projectile / kinematics simulator.
 * <div data-ps-app="simulator-kinematics"></div>
 * A dark-panel accent (uses the #101426 ink token, not a separate palette).
 * Launch controls -> canvas trajectory + live data table + equation strip.
 * Honors prefers-reduced-motion (draws the full path instantly).
 */
(function () {
  "use strict";
  var PS = window.PS;

  PS.register("simulator-kinematics", async function (el) {
    el.innerHTML = "";
    var state = { v: 20, angle: 45, h: 0, g: 9.8 };

    var canvas = PS.h("canvas.ps-sim-canvas", { role: "img",
      "aria-label": "Projectile trajectory" });
    var ctx = canvas.getContext("2d");

    var readout = PS.h("div.ps-sim-readout", { "aria-live": "polite" });
    var tableWrap = PS.h("div.ps-sim-tablewrap");
    var eqStrip = PS.h("div.ps-sim-eqstrip.ps-mono");

    var controls = PS.h("div.ps-sim-controls", {}, [
      slider("Launch speed", "v", 1, 60, 1, "m/s"),
      slider("Angle", "angle", 0, 90, 1, "°"),
      slider("Initial height", "h", 0, 50, 1, "m"),
      gravitySelect()
    ]);

    var launchBtn = PS.h("button.ps-btn", { type: "button" }, "▶ Launch");
    var resetBtn = PS.h("button.ps-btn.ps-btn--ghost.ps-btn--on-dark", { type: "button" }, "Reset");
    launchBtn.addEventListener("click", function () { run(); });
    resetBtn.addEventListener("click", function () { compute(); drawStatic(); });
    var buttons = PS.h("div.ps-sim-buttons", {}, [launchBtn, resetBtn]);

    var panel = PS.h("div.ps-sim.ps-sim--dark", {}, [
      PS.h("div.ps-sim-head", {}, [
        PS.h("h2.ps-sim-title", {}, "Kinematics Simulator"),
        PS.h("p.ps-sim-sub", {}, "Projectile launcher — adjust the controls and launch.")
      ]),
      PS.h("div.ps-sim-grid", {}, [
        PS.h("div.ps-sim-left", {}, [canvas, eqStrip]),
        PS.h("div.ps-sim-right", {}, [controls, buttons, readout, tableWrap])
      ])
    ]);
    el.appendChild(panel);
    PS.reveal(panel);

    var traj = [];
    var meta = {};
    var raf = null;

    function slider(label, key, min, max, step, unit) {
      var id = "ps-sim-" + key;
      var out = PS.h("output.ps-sim-val.ps-mono", { for: id }, state[key] + unit);
      var input = PS.h("input.ps-sim-range", {
        id: id, type: "range", min: min, max: max, step: step, value: state[key]
      });
      input.addEventListener("input", function () {
        state[key] = parseFloat(input.value);
        out.textContent = state[key] + unit;
        compute(); drawStatic();
      });
      return PS.h("div.ps-sim-control", {}, [
        PS.h("label.ps-sim-label", { for: id }, [label, out]),
        input
      ]);
    }

    function gravitySelect() {
      var id = "ps-sim-g";
      var sel = PS.h("select.ps-sim-select", { id: id });
      [["Earth", 9.8], ["Moon", 1.6], ["Mars", 3.7], ["Jupiter", 24.8]].forEach(function (o) {
        sel.appendChild(PS.h("option", { value: o[1] }, o[0] + " (" + o[1] + " m/s²)"));
      });
      sel.value = String(state.g);
      sel.addEventListener("change", function () {
        state.g = parseFloat(sel.value); compute(); drawStatic();
      });
      return PS.h("div.ps-sim-control", {}, [
        PS.h("label.ps-sim-label", { for: id }, "Gravity"),
        sel
      ]);
    }

    function compute() {
      var rad = state.angle * Math.PI / 180;
      var vx = state.v * Math.cos(rad);
      var vy0 = state.v * Math.sin(rad);
      var g = state.g, h = state.h;
      var tFlight = (vy0 + Math.sqrt(vy0 * vy0 + 2 * g * h)) / g;
      var range = vx * tFlight;
      var maxH = h + (vy0 * vy0) / (2 * g);
      meta = { vx: vx, vy0: vy0, tFlight: tFlight, range: range, maxH: maxH };

      traj = [];
      var N = 240;
      for (var i = 0; i <= N; i++) {
        var t = tFlight * i / N;
        traj.push({ t: t, x: vx * t, y: Math.max(0, h + vy0 * t - 0.5 * g * t * t),
          vx: vx, vy: vy0 - g * t });
      }

      eqStrip.innerHTML = "";
      [
        "x = v₀cosθ · t",
        "y = y₀ + v₀sinθ · t − ½gt²",
        "R = " + meta.range.toFixed(1) + " m",
        "t = " + meta.tFlight.toFixed(2) + " s",
        "H = " + meta.maxH.toFixed(1) + " m"
      ].forEach(function (s) { eqStrip.appendChild(PS.h("span.ps-sim-eq", {}, s)); });

      readout.textContent = "Range " + meta.range.toFixed(1) + " m · flight time " +
        meta.tFlight.toFixed(2) + " s · peak height " + meta.maxH.toFixed(1) + " m.";

      renderTable();
    }

    function renderTable() {
      tableWrap.innerHTML = "";
      var table = PS.h("table.ps-sim-table", {});
      var thead = PS.h("thead", {}, PS.h("tr", {}, ["t (s)", "x (m)", "y (m)", "vₓ (m/s)", "v_y (m/s)"].map(function (h) {
        return PS.h("th", { scope: "col" }, h);
      })));
      var tbody = PS.h("tbody");
      var rows = 8;
      for (var i = 0; i <= rows; i++) {
        var p = traj[Math.round(traj.length ? (traj.length - 1) * i / rows : 0)] || { t: 0, x: 0, y: 0, vx: 0, vy: 0 };
        tbody.appendChild(PS.h("tr", {}, [
          p.t.toFixed(2), p.x.toFixed(1), p.y.toFixed(1), p.vx.toFixed(1), p.vy.toFixed(1)
        ].map(function (c) { return PS.h("td.ps-mono", {}, c); })));
      }
      table.appendChild(thead); table.appendChild(tbody);
      tableWrap.appendChild(table);
    }

    function fit() {
      var w = canvas.clientWidth || 480;
      var h = Math.max(220, Math.round(w * 0.6));
      var dpr = window.devicePixelRatio || 1;
      canvas.width = w * dpr; canvas.height = h * dpr;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      return { w: w, h: h };
    }

    function mapper(size) {
      var pad = 28;
      var maxX = Math.max(meta.range, 1);
      var maxY = Math.max(meta.maxH, state.h, 1) * 1.1;
      var sx = (size.w - pad * 2) / maxX;
      var sy = (size.h - pad * 2) / maxY;
      return {
        X: function (x) { return pad + x * sx; },
        Y: function (y) { return size.h - pad - y * sy; }
      };
    }

    function drawFrame(upto) {
      var size = fit();
      var m = mapper(size);
      ctx.clearRect(0, 0, size.w, size.h);
      // ground
      ctx.strokeStyle = "rgba(255,255,255,.18)";
      ctx.lineWidth = 1;
      ctx.beginPath(); ctx.moveTo(20, m.Y(0)); ctx.lineTo(size.w - 12, m.Y(0)); ctx.stroke();
      // full faint path
      strokePath(m, traj.length - 1, "rgba(255,255,255,.15)", 1.5);
      // travelled path
      strokePath(m, upto, "#5f7cf0", 2.5);
      // projectile
      var p = traj[Math.min(upto, traj.length - 1)];
      if (p) {
        ctx.fillStyle = "#ffffff";
        ctx.beginPath(); ctx.arc(m.X(p.x), m.Y(p.y), 5, 0, Math.PI * 2); ctx.fill();
      }
      // apex marker
      ctx.fillStyle = "rgba(255,255,255,.55)";
      ctx.font = "11px 'JetBrains Mono', monospace";
      ctx.fillText("apex " + meta.maxH.toFixed(1) + " m", m.X(meta.range / 2) - 24, m.Y(meta.maxH) - 8);
    }

    function strokePath(m, upto, color, width) {
      if (!traj.length) return;
      ctx.strokeStyle = color; ctx.lineWidth = width;
      ctx.beginPath();
      for (var i = 0; i <= upto && i < traj.length; i++) {
        var q = traj[i];
        if (i === 0) ctx.moveTo(m.X(q.x), m.Y(q.y));
        else ctx.lineTo(m.X(q.x), m.Y(q.y));
      }
      ctx.stroke();
    }

    function drawStatic() { drawFrame(traj.length - 1); }

    function run() {
      if (raf) cancelAnimationFrame(raf);
      if (PS.reducedMotion()) { drawStatic(); return; }
      var start = null;
      var duration = Math.min(2400, Math.max(700, meta.tFlight * 600));
      function tick(ts) {
        if (start == null) start = ts;
        var k = Math.min(1, (ts - start) / duration);
        drawFrame(Math.round(k * (traj.length - 1)));
        if (k < 1) raf = requestAnimationFrame(tick);
      }
      raf = requestAnimationFrame(tick);
    }

    var resizeTimer;
    window.addEventListener("resize", function () {
      clearTimeout(resizeTimer);
      resizeTimer = setTimeout(drawStatic, 120);
    });

    compute();
    // Canvas needs layout before first draw.
    requestAnimationFrame(drawStatic);
  });
})();

/* --- src/js/components/portfolio.js --- */
/* Physics Solved — portfolio.
 * <div data-ps-app="portfolio"></div>
 * Hero intro, filter pills (All / Engineering / Coding / Physics Tools), a
 * responsive card grid (featured cards larger) that expands in place — no modal.
 * Data from data/portfolio.json.
 */
(function () {
  "use strict";
  var PS = window.PS;

  var TAGS = [
    { id: "all", label: "All" },
    { id: "engineering", label: "Engineering" },
    { id: "coding", label: "Coding" },
    { id: "physics-tools", label: "Physics Tools" }
  ];
  var TAG_LABEL = { engineering: "Engineering", coding: "Coding", "physics-tools": "Physics Tools" };

  PS.register("portfolio", async function (el) {
    var data = await PS.fetchJSON("portfolio.json");
    el.innerHTML = "";
    var projects = data.projects || [];
    var filter = "all";

    if (data.intro) el.appendChild(PS.h("p.ps-portfolio-intro", {}, data.intro));

    var pills = PS.h("div.ps-pills", { role: "tablist", "aria-label": "Filter projects" });
    var pillBtns = {};
    TAGS.forEach(function (t) {
      var btn = PS.h("button.ps-pill", { type: "button", role: "tab",
        "aria-selected": t.id === filter ? "true" : "false" }, t.label);
      btn.addEventListener("click", function () { setFilter(t.id); });
      pillBtns[t.id] = btn;
      pills.appendChild(btn);
    });
    el.appendChild(pills);

    var grid = PS.h("div.ps-portfolio-grid");
    el.appendChild(grid);
    PS.reveal(grid);

    var cards = projects.map(function (p) { return { project: p, node: card(p) }; });
    cards.forEach(function (c) { grid.appendChild(c.node); });
    apply();

    function setFilter(id) {
      filter = id;
      Object.keys(pillBtns).forEach(function (k) {
        pillBtns[k].setAttribute("aria-selected", k === id ? "true" : "false");
      });
      apply();
    }

    function apply() {
      var shown = 0;
      cards.forEach(function (c) {
        var tags = c.project.tags || [];
        var match = filter === "all" || tags.indexOf(filter) !== -1;
        c.node.hidden = !match;
        if (match) shown++;
      });
      var empty = grid.querySelector(".ps-portfolio-empty");
      if (!shown && !empty) grid.appendChild(PS.h("div.ps-portfolio-empty.ps-state", {}, "No projects in this filter."));
      else if (shown && empty) empty.remove();
    }
  });

  function card(p) {
    var featured = !!p.featured;
    var cover = coverNode(p);

    var chips = PS.h("div.ps-chips", {}, (p.tags || []).map(function (t) {
      return PS.h("span.ps-chip", {}, TAG_LABEL[t] || t);
    }));

    var tech = (p.tech && p.tech.length)
      ? PS.h("ul.ps-tech", { "aria-label": "Tech used" }, p.tech.map(function (t) {
          return PS.h("li.ps-tech-item.ps-mono", {}, t);
        }))
      : null;

    var links = (p.links && p.links.length)
      ? PS.h("div.ps-portfolio-links", {}, p.links.map(function (l) {
          return PS.h("a.ps-link", { href: l.url,
            target: /^https?:/.test(l.url || "") ? "_blank" : null,
            rel: /^https?:/.test(l.url || "") ? "noopener" : null }, l.label);
        }))
      : null;

    var descId = "ps-proj-" + (p.id || Math.random().toString(36).slice(2));
    var desc = PS.h("div.ps-portfolio-desc", { id: descId, hidden: true },
      PS.h("p", {}, p.description || ""));

    var toggle = p.description
      ? PS.h("button.ps-portfolio-toggle", { type: "button",
          "aria-expanded": "false", "aria-controls": descId }, "Read more")
      : null;
    if (toggle) {
      toggle.addEventListener("click", function () {
        var open = toggle.getAttribute("aria-expanded") === "true";
        toggle.setAttribute("aria-expanded", open ? "false" : "true");
        toggle.textContent = open ? "Read more" : "Show less";
        desc.hidden = open;
      });
    }

    return PS.h("article.ps-card.ps-portfolio-card" + (featured ? ".is-featured" : ""), {}, [
      cover,
      PS.h("div.ps-portfolio-body", {}, [
        PS.h("div.ps-portfolio-titlerow", {}, [
          PS.h("h3.ps-portfolio-title", {}, p.title || "Untitled"),
          p.year ? PS.h("span.ps-portfolio-year.ps-mono", {}, String(p.year)) : null
        ]),
        chips,
        p.summary ? PS.h("p.ps-portfolio-summary", {}, p.summary) : null,
        tech,
        links,
        toggle,
        desc
      ])
    ]);
  }

  function coverNode(p) {
    if (p.images && p.images.length) {
      return PS.h("div.ps-portfolio-cover", {}, PS.h("img.ps-portfolio-img", {
        src: p.images[0], alt: p.title || "", loading: "lazy" }));
    }
    var hue = hash(p.title || p.id || "x") % 360;
    return PS.h("div.ps-portfolio-cover.ps-portfolio-cover--gradient", {
      style: "--ps-h:" + hue, "aria-hidden": "true"
    }, PS.h("span.ps-portfolio-cover-mark", {}, (p.title || "•").slice(0, 1).toUpperCase()));
  }

  function hash(s) {
    var h = 0;
    for (var i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) >>> 0;
    return h;
  }
})();

/* --- src/js/components/periodic-table.js --- */
/* Physics Solved — periodic table.
 * <div data-ps-app="periodic-table"></div>
 * Full 118-element table from data/periodic-table.json. Color by category,
 * click for a detail panel, search by name/symbol, category legend that filters.
 * Keyboard: Tab to cells, Enter to open, arrow keys to move. Mobile: the grid
 * scrolls horizontally with a sticky group-number header.
 */
(function () {
  "use strict";
  var PS = window.PS;

  PS.register("periodic-table", async function (el) {
    var data = await PS.fetchJSON("periodic-table.json");
    el.innerHTML = "";
    var elements = data.elements || [];
    var cats = data.categories || [];
    var catLabel = {};
    cats.forEach(function (c) { catLabel[c.id] = c.label; });

    var query = "", activeCat = null;
    var byNumber = {};
    elements.forEach(function (e) { byNumber[e.number] = e; });

    /* Search + legend */
    var search = PS.h("input.ps-pt-search", { type: "search",
      placeholder: "Search element by name or symbol…", "aria-label": "Search elements" });
    search.addEventListener("input", function () { query = search.value.trim().toLowerCase(); apply(); });

    var legend = PS.h("div.ps-pt-legend", { role: "group", "aria-label": "Filter by category" });
    cats.forEach(function (c) {
      var chip = PS.h("button.ps-pt-legchip", { type: "button", "data-cat": c.id, "aria-pressed": "false" }, [
        PS.h("span.ps-pt-swatch", { "data-cat": c.id, "aria-hidden": "true" }), c.label
      ]);
      chip.addEventListener("click", function () {
        activeCat = activeCat === c.id ? null : c.id;
        legend.querySelectorAll(".ps-pt-legchip").forEach(function (x) {
          x.setAttribute("aria-pressed", String(x.getAttribute("data-cat") === activeCat));
        });
        apply();
      });
      legend.appendChild(chip);
    });

    /* Grid */
    var grid = PS.h("div.ps-pt-grid", { role: "grid", "aria-label": "Periodic table" });
    // Group-number header row (row 1)
    for (var g = 1; g <= 18; g++) {
      grid.appendChild(PS.h("div.ps-pt-grouphead", { style: "grid-column:" + g + ";grid-row:1", "aria-hidden": "true" }, String(g)));
    }
    var cells = [];
    elements.forEach(function (e) {
      var col, row;
      if (e.group == null) {
        // f-block: lanthanides row 9, actinides row 10, columns 3..17 by atomic number
        if (e.number >= 57 && e.number <= 71) { row = 9; col = (e.number - 57) + 3; }
        else if (e.number >= 89 && e.number <= 103) { row = 10; col = (e.number - 89) + 3; }
        else { return; }
      } else {
        col = e.group; row = e.period + 1;
      }
      var cell = PS.h("button.ps-pt-el", {
        type: "button", role: "gridcell",
        "data-cat": e.category, "data-num": e.number,
        style: "grid-column:" + col + ";grid-row:" + row,
        "aria-label": e.name + ", atomic number " + e.number
      }, [
        PS.h("span.ps-pt-num", {}, String(e.number)),
        PS.h("span.ps-pt-sym", {}, e.symbol),
        PS.h("span.ps-pt-mass", {}, fmtMass(e.mass))
      ]);
      cell.addEventListener("click", function () { showDetail(e); focusCell(e.number); });
      cell.addEventListener("keydown", function (ev) { onKey(ev, e); });
      cells.push({ e: e, node: cell });
      grid.appendChild(cell);
    });
    // f-block placeholder markers in the main table (group 3, periods 6 & 7)
    grid.appendChild(PS.h("div.ps-pt-el.ps-pt-fmarker", { style: "grid-column:3;grid-row:7", "aria-hidden": "true" }, "57–71"));
    grid.appendChild(PS.h("div.ps-pt-el.ps-pt-fmarker", { style: "grid-column:3;grid-row:8", "aria-hidden": "true" }, "89–103"));

    var scroller = PS.h("div.ps-pt-scroller", {}, grid);
    var detail = PS.h("div.ps-pt-detail", { role: "region", "aria-live": "polite" });
    detail.appendChild(PS.h("p.ps-muted", {}, "Select an element to see its details."));

    el.appendChild(PS.h("div.ps-pt-controls", {}, [search, legend]));
    el.appendChild(scroller);
    el.appendChild(detail);
    PS.reveal(scroller);

    function apply() {
      cells.forEach(function (c) {
        var e = c.e;
        var matchQ = !query || e.name.toLowerCase().indexOf(query) !== -1 || e.symbol.toLowerCase().indexOf(query) === 0 || e.symbol.toLowerCase() === query;
        var matchC = !activeCat || e.category === activeCat;
        c.node.classList.toggle("is-dim", !(matchQ && matchC));
      });
    }

    function focusCell(num) {
      var found = cells.find(function (c) { return c.e.number === num; });
      if (found) found.node.focus();
    }

    function onKey(ev, e) {
      var target = null;
      if (ev.key === "ArrowRight") target = e.number + 1;
      else if (ev.key === "ArrowLeft") target = e.number - 1;
      else if (ev.key === "ArrowUp" && e.group != null) target = numberAt(e.group, e.period - 1);
      else if (ev.key === "ArrowDown" && e.group != null) target = numberAt(e.group, e.period + 1);
      else return;
      if (target && byNumber[target]) { ev.preventDefault(); focusCell(target); showDetail(byNumber[target]); }
    }
    function numberAt(group, period) {
      var m = cells.find(function (c) { return c.e.group === group && c.e.period === period; });
      return m ? m.e.number : null;
    }

    function showDetail(e) {
      detail.innerHTML = "";
      var rows = [
        ["Atomic number", e.number],
        ["Atomic mass", fmtMass(e.mass) + " u"],
        ["Category", catLabel[e.category] || e.category],
        ["Group / Period", (e.group == null ? "f-block" : e.group) + " / " + e.period],
        ["Electronegativity", e.electronegativity == null ? "—" : e.electronegativity],
        ["Common oxidation states", (e.oxidationStates && e.oxidationStates.length) ? e.oxidationStates.map(sign).join(", ") : "—"]
      ];
      var dl = PS.h("dl.ps-pt-dl");
      rows.forEach(function (r) {
        dl.appendChild(PS.h("dt", {}, r[0]));
        dl.appendChild(PS.h("dd.ps-mono", {}, String(r[1])));
      });
      detail.appendChild(PS.h("div.ps-pt-detail-head", { "data-cat": e.category }, [
        PS.h("span.ps-pt-detail-sym", {}, e.symbol),
        PS.h("div", {}, [
          PS.h("h4.ps-pt-detail-name", {}, e.name),
          PS.h("span.ps-pt-detail-cat", {}, catLabel[e.category] || e.category)
        ])
      ]));
      detail.appendChild(dl);
      if (e.todo) detail.appendChild(PS.h("p.ps-pt-todo", {}, "⚠ Properties for this element are predicted/uncertain."));
    }
  });

  function fmtMass(m) {
    if (m == null) return "—";
    return (m >= 100 || m % 1 === 0) ? String(m) : m.toFixed(3);
  }
  function sign(n) { return n > 0 ? "+" + n : String(n); }
})();

/* --- src/js/components/molar-mass.js --- */
/* Physics Solved — molar mass calculator.
 * <div data-ps-app="molar-mass"></div>
 * Parses a chemical formula (nested parentheses/brackets and dot-hydrates like
 * CuSO4·5H2O) and reports the molar mass with a per-element breakdown.
 * Reuses atomic masses from data/periodic-table.json.
 */
(function () {
  "use strict";
  var PS = window.PS;
  var SUBS = { "₀": "0", "₁": "1", "₂": "2", "₃": "3", "₄": "4", "₅": "5", "₆": "6", "₇": "7", "₈": "8", "₉": "9" };

  PS.register("molar-mass", async function (el) {
    var data = await PS.fetchJSON("periodic-table.json");
    var mass = {}, name = {};
    (data.elements || []).forEach(function (e) { mass[e.symbol] = e.mass; name[e.symbol] = e.name; });
    el.innerHTML = "";

    var input = PS.h("input.ps-mm-input.ps-mono", { type: "text",
      placeholder: "e.g. Fe2(SO4)3 or CuSO4·5H2O", "aria-label": "Chemical formula" });
    var out = PS.h("div.ps-mm-out", { role: "region", "aria-live": "polite" });

    var examples = PS.h("div.ps-mm-examples", {}, ["H2O", "Fe2(SO4)3", "CuSO4·5H2O", "C6H12O6", "Ca(OH)2", "KMnO4"]
      .map(function (f) {
        var b = PS.h("button.ps-chip.ps-mm-ex", { type: "button" }, f);
        b.addEventListener("click", function () { input.value = f; compute(); });
        return b;
      }));

    input.addEventListener("input", compute);
    el.appendChild(PS.h("div.ps-mm-controls", {}, [
      PS.h("label.ps-mm-label", { for: "" }, "Chemical formula"), input, examples
    ]));
    el.appendChild(out);
    PS.reveal(out);

    function compute() {
      var raw = input.value.trim();
      out.innerHTML = "";
      if (!raw) { out.appendChild(PS.h("p.ps-muted", {}, "Enter a formula to compute its molar mass.")); return; }
      var counts;
      try { counts = parse(raw); }
      catch (err) { out.appendChild(PS.h("p.ps-state--error", {}, err.message)); return; }

      var syms = Object.keys(counts);
      var unknown = syms.filter(function (s) { return mass[s] == null; });
      if (unknown.length) {
        out.appendChild(PS.h("p.ps-state--error", {}, "Unknown element symbol(s): " + unknown.join(", ")));
        return;
      }
      var total = 0;
      syms.forEach(function (s) { total += mass[s] * counts[s]; });

      out.appendChild(PS.h("div.ps-mm-total", {}, [
        PS.h("span.ps-mm-total-label", {}, "Molar mass"),
        PS.h("span.ps-mm-total-val.ps-mono", {}, total.toFixed(3) + " g/mol")
      ]));

      var table = PS.h("table.ps-mm-table", {}, [
        PS.h("thead", {}, PS.h("tr", {}, ["Element", "Count", "Atomic mass", "Subtotal", "% mass"].map(function (h) {
          return PS.h("th", { scope: "col" }, h);
        }))),
        PS.h("tbody", {}, syms.sort().map(function (s) {
          var sub = mass[s] * counts[s];
          return PS.h("tr", {}, [
            PS.h("td", {}, [PS.h("span.ps-mono", {}, s), " ", PS.h("span.ps-muted", {}, name[s] || "")]),
            PS.h("td.ps-mono", {}, String(counts[s])),
            PS.h("td.ps-mono", {}, mass[s].toFixed(3)),
            PS.h("td.ps-mono", {}, sub.toFixed(3)),
            PS.h("td.ps-mono", {}, (100 * sub / total).toFixed(2) + "%")
          ]);
        }))
      ]);
      out.appendChild(PS.h("div.ps-mm-tablewrap", {}, table));
    }
  });

  // Returns { symbol: count }. Throws on malformed input.
  function parse(formula) {
    var f = String(formula).replace(/[₀-₉]/g, function (c) { return SUBS[c]; }).replace(/\s+/g, "");
    // Split hydrates on middle-dot / bullet / asterisk / period.
    var segs = f.split(/[·•.*]/).filter(Boolean);
    var total = {};
    segs.forEach(function (seg) {
      var m = seg.match(/^(\d+)(.+)$/);
      var coeff = 1, body = seg;
      if (m && /[A-Za-z(\[]/.test(m[2][0])) { coeff = parseInt(m[1], 10); body = m[2]; }
      var counts = parseGroup(body);
      Object.keys(counts).forEach(function (s) { total[s] = (total[s] || 0) + counts[s] * coeff; });
    });
    if (!Object.keys(total).length) throw new Error("Could not parse the formula.");
    return total;
  }

  function parseGroup(str) {
    var stack = [{}];
    var i = 0, n = str.length;
    while (i < n) {
      var ch = str[i];
      if (ch === "(" || ch === "[") { stack.push({}); i++; }
      else if (ch === ")" || ch === "]") {
        i++;
        var num = readNum(str, i); i = num.i;
        var top = stack.pop();
        if (!stack.length) throw new Error("Unbalanced parentheses.");
        var parent = stack[stack.length - 1];
        Object.keys(top).forEach(function (s) { parent[s] = (parent[s] || 0) + top[s] * num.v; });
      } else if (/[A-Z]/.test(ch)) {
        var sym = ch; i++;
        while (i < n && /[a-z]/.test(str[i])) { sym += str[i]; i++; }
        var c = readNum(str, i); i = c.i;
        var m = stack[stack.length - 1];
        m[sym] = (m[sym] || 0) + c.v;
      } else {
        throw new Error("Unexpected character “" + ch + "” in formula.");
      }
    }
    if (stack.length !== 1) throw new Error("Unbalanced parentheses.");
    return stack[0];
  }

  function readNum(str, i) {
    var s = "";
    while (i < str.length && /\d/.test(str[i])) { s += str[i]; i++; }
    return { v: s ? parseInt(s, 10) : 1, i: i };
  }
})();

/* --- src/js/components/unit-converter.js --- */
/* Physics Solved — unit converter.
 * <div data-ps-app="unit-converter"></div>
 * Quantities and units from data/units.json (factors to SI base). Temperature
 * is offset-aware. Add units/quantities in JSON — no JS changes.
 */
(function () {
  "use strict";
  var PS = window.PS;

  PS.register("unit-converter", async function (el) {
    var data = await PS.fetchJSON("units.json");
    var quantities = data.quantities || [];
    el.innerHTML = "";
    if (!quantities.length) { el.appendChild(PS.h("div.ps-state", {}, "No units configured.")); return; }

    var qSel = PS.h("select.ps-uc-select", { "aria-label": "Quantity" });
    quantities.forEach(function (q) { qSel.appendChild(PS.h("option", { value: q.id }, q.label)); });

    var valIn = PS.h("input.ps-uc-value.ps-mono", { type: "number", value: "1", step: "any", "aria-label": "Value to convert" });
    var fromSel = PS.h("select.ps-uc-select", { "aria-label": "From unit" });
    var toSel = PS.h("select.ps-uc-select", { "aria-label": "To unit" });
    var swap = PS.h("button.ps-btn.ps-btn--ghost.ps-uc-swap", { type: "button", "aria-label": "Swap units" }, "⇄");
    var result = PS.h("div.ps-uc-result.ps-mono", { role: "status", "aria-live": "polite" });

    var current;
    function loadQuantity() {
      current = quantities.find(function (q) { return q.id === qSel.value; }) || quantities[0];
      fromSel.innerHTML = ""; toSel.innerHTML = "";
      current.units.forEach(function (u) {
        fromSel.appendChild(PS.h("option", { value: u.id }, u.label));
        toSel.appendChild(PS.h("option", { value: u.id }, u.label));
      });
      if (current.units[1]) toSel.value = current.units[1].id;
      convert();
    }

    function toBase(q, unitId, v) {
      if (q.special === "temperature") {
        if (unitId === "K") return v;
        if (unitId === "C") return v + 273.15;
        if (unitId === "F") return (v - 32) * 5 / 9 + 273.15;
      }
      return v * unitById(q, unitId).factor;
    }
    function fromBase(q, unitId, base) {
      if (q.special === "temperature") {
        if (unitId === "K") return base;
        if (unitId === "C") return base - 273.15;
        if (unitId === "F") return (base - 273.15) * 9 / 5 + 32;
      }
      return base / unitById(q, unitId).factor;
    }
    function unitById(q, id) { return q.units.find(function (u) { return u.id === id; }); }

    function convert() {
      var v = parseFloat(valIn.value);
      if (isNaN(v)) { result.textContent = "Enter a number."; return; }
      var base = toBase(current, fromSel.value, v);
      var res = fromBase(current, toSel.value, base);
      result.textContent = v + " " + labelOf(fromSel) + "  =  " + fmt(res) + " " + labelOf(toSel);
    }
    function labelOf(sel) { return sel.options[sel.selectedIndex].text.replace(/\s*\(.*\)$/, ""); }
    function fmt(x) {
      if (x === 0) return "0";
      var a = Math.abs(x);
      if (a >= 1e6 || a < 1e-4) return x.toExponential(4);
      return String(Math.round(x * 1e6) / 1e6);
    }

    qSel.addEventListener("change", loadQuantity);
    [valIn, fromSel, toSel].forEach(function (n) { n.addEventListener("input", convert); n.addEventListener("change", convert); });
    swap.addEventListener("click", function () {
      var t = fromSel.value; fromSel.value = toSel.value; toSel.value = t; convert();
    });

    el.appendChild(PS.h("div.ps-uc-row", {}, [PS.h("label.ps-uc-label", {}, "Quantity"), qSel]));
    el.appendChild(PS.h("div.ps-uc-convert", {}, [
      PS.h("div.ps-uc-field", {}, [valIn, fromSel]),
      swap,
      PS.h("div.ps-uc-field", {}, [PS.h("div.ps-uc-spacer", { "aria-hidden": "true" }), toSel])
    ]));
    el.appendChild(result);
    PS.reveal(el.firstChild);
    loadQuantity();
  });
})();

/* --- src/js/components/constants.js --- */
/* Physics Solved — constants library.
 * <div data-ps-app="constants"></div>
 * Searchable physics + chemistry constants from data/constants.json.
 */
(function () {
  "use strict";
  var PS = window.PS;

  PS.register("constants", async function (el) {
    var data = await PS.fetchJSON("constants.json");
    var items = data.constants || [];
    el.innerHTML = "";

    var query = "", activeCat = null;
    var cats = [];
    items.forEach(function (c) { if (cats.indexOf(c.category) === -1) cats.push(c.category); });

    var search = PS.h("input.ps-const-search", { type: "search",
      placeholder: "Search constants by name or symbol…", "aria-label": "Search constants" });
    search.addEventListener("input", function () { query = search.value.trim().toLowerCase(); render(); });

    var filter = PS.h("div.ps-pills.ps-const-filter", { role: "group", "aria-label": "Filter by category" });
    [{ id: null, label: "All" }].concat(cats.map(function (c) { return { id: c, label: cap(c) }; })).forEach(function (c) {
      var b = PS.h("button.ps-pill", { type: "button", "aria-pressed": String(c.id === activeCat) }, c.label);
      b.addEventListener("click", function () {
        activeCat = c.id;
        filter.querySelectorAll(".ps-pill").forEach(function (x) { x.setAttribute("aria-pressed", "false"); });
        b.setAttribute("aria-pressed", "true");
        render();
      });
      filter.appendChild(b);
    });

    var list = PS.h("div.ps-const-list", { role: "list" });
    el.appendChild(PS.h("div.ps-const-controls", {}, [search, filter]));
    el.appendChild(list);
    PS.reveal(list);
    render();

    function render() {
      list.innerHTML = "";
      var shown = items.filter(function (c) {
        var q = !query || (c.name + " " + c.symbol).toLowerCase().indexOf(query) !== -1;
        var cat = !activeCat || c.category === activeCat;
        return q && cat;
      });
      if (!shown.length) { list.appendChild(PS.h("div.ps-state", {}, "No constants match your search.")); return; }
      shown.forEach(function (c) {
        list.appendChild(PS.h("div.ps-const-item", { role: "listitem" }, [
          PS.h("span.ps-const-sym.ps-mono", {}, c.symbol),
          PS.h("div.ps-const-body", {}, [
            PS.h("span.ps-const-name", {}, c.name),
            PS.h("span.ps-const-val.ps-mono", {}, c.value + " " + c.units)
          ]),
          PS.h("span.ps-const-tag" + (c.exact ? ".is-exact" : ""), { title: c.exact ? "Exact by SI definition" : "Measured / rounded value" }, c.exact ? "exact" : "measured")
        ]));
      });
    }
  });

  function cap(s) { return String(s).charAt(0).toUpperCase() + String(s).slice(1); }
})();

/* --- src/js/components/search.js --- */
/* Physics Solved — global search.
 * <div data-ps-app="search"></div>  (mount on the home page)
 * Client-side index of registry courses + every equation and formula-sheet row.
 * Typing e.g. "momentum" surfaces matching equations/rows with links to the
 * owning course page. Index is built once from the same JSON the tools use.
 */
(function () {
  "use strict";
  var PS = window.PS;

  PS.register("search", async function (el) {
    el.innerHTML = "";
    var input = PS.h("input.ps-search-input", { type: "search",
      placeholder: "Search equations, sheets, courses… (e.g. “momentum”, “pH”)",
      "aria-label": "Search the site", autocomplete: "off" });
    var results = PS.h("div.ps-search-results", { role: "listbox", "aria-label": "Search results" });
    var status = PS.h("div.ps-search-status.ps-muted", {}, "Building index…");
    el.appendChild(PS.h("div.ps-search-box", {}, [input, status]));
    el.appendChild(results);
    PS.reveal(el.firstChild);

    var index = await buildIndex();
    status.textContent = index.length + " entries indexed.";

    var timer;
    input.addEventListener("input", function () {
      clearTimeout(timer);
      timer = setTimeout(run, 120);
    });

    function run() {
      var q = input.value.trim().toLowerCase();
      results.innerHTML = "";
      if (q.length < 2) { status.textContent = index.length + " entries indexed."; return; }
      var hits = index.filter(function (e) { return e.hay.indexOf(q) !== -1; }).slice(0, 40);
      status.textContent = hits.length ? hits.length + " result" + (hits.length === 1 ? "" : "s") : "No matches.";
      hits.forEach(function (e) {
        var node;
        var inner = PS.h("div.ps-search-hit-body", {}, [
          PS.h("span.ps-search-hit-kind", {}, e.kindLabel),
          PS.h("span.ps-search-hit-main", {}, e.title),
          e.expr ? PS.h("span.ps-search-hit-expr.ps-mono", {}, e.expr) : null,
          PS.h("span.ps-search-hit-src", {}, e.source)
        ]);
        if (e.url) {
          node = PS.h("a.ps-search-hit", { href: e.url, role: "option" }, inner);
        } else {
          node = PS.h("div.ps-search-hit.is-static", { role: "option" }, inner);
        }
        results.appendChild(node);
      });
    }

    async function buildIndex() {
      var reg = await PS.getRegistry();
      var entries = [];
      var jobs = [];
      (reg.subjects || []).forEach(function (subj) {
        (subj.courses || []).forEach(function (course) {
          entries.push(mk("course", "Course", course.label,
            (course.eyebrow || "") + " " + (course.blurb || ""), null, course.url, subj.label + " · course"));
          if ((course.features || []).indexOf("equation-finder") !== -1) {
            jobs.push(PS.fetchJSON("equations/" + course.id + ".json").then(function (eq) {
              (eq.units || []).forEach(function (u) {
                (u.equations || []).forEach(function (e) {
                  entries.push(mk("equation", "Equation", e.name, e.name + " " + e.expr, e.expr, course.url, course.label + " · " + u.title));
                });
              });
            }).catch(function () {}));
          }
          (course.sheets || []).forEach(function (sh) {
            jobs.push(PS.fetchJSON(sh.file).then(function (sheet) {
              (sheet.categories || []).forEach(function (cat) {
                (cat.rows || []).forEach(function (r) {
                  entries.push(mk("sheet", "Sheet row", r.name, r.name + " " + r.expr, r.expr, course.url, sh.label + " · " + cat.title));
                });
              });
            }).catch(function () {}));
          });
        });
      });
      await Promise.all(jobs);
      return entries;
    }

    function mk(kind, kindLabel, title, hayText, expr, url, source) {
      return { kind: kind, kindLabel: kindLabel, title: title, expr: expr, url: url, source: source,
        hay: (hayText + " " + source).toLowerCase() };
    }
  });
})();

